('Tecnología','¿Qué comandos de PyTorch 1.8 producen una matriz gaussiana $10\times 5$ con cada entrada de i.i.d tomada de $\mathcal{N}(\mu=5,\sigma^2=16)$ y una matriz uniforme $10\times 10$ con cada entrada de i.i.d. tomada de $U[-1,1)$?','MULTIPLE_CHOICE','\texttt{5 + torch.randn(10,5) * 16} ; \texttt{torch.rand(10,10,low=-1,high=1)}','\texttt{5 + torch.randn(10,5) * 16} ; \texttt{(torch.rand(10,10) - 0.5) / 0.5}','\texttt{5 + torch.randn(10,5) * 4} ; \texttt{2 * torch.rand(10,10) - 1}','\texttt{torch.normal(torch.ones(10,5)*5,torch.ones(5,5)*16)} ; \texttt{2 * torch.rand(10,10) - 1}','C',NULL,NULL,'MEDIUM','MMMLU'),
